// generar_247_badge_medicamentos_fix.js
// CHIQUI Entre Señales — Fix: badge "1 activo" con dosis finalizada
//
// El badge del encabezado de Medicamentos decía "1 activo" mientras
// la tarjeta del medicamento ya mostraba "Finalizado" (por fecha_fin
// pasada). Misma raíz que el bug del 246: se contaban los que tenían
// estado='activo' en la base sin considerar fecha_fin.
//
// Fix: el conteo aplica la misma lógica DERIVADA que la tarjeta —
// activo solo si estado='activo' Y (sin fecha_fin O fecha_fin >= hoy).
//
// Solo reescribe app/prevencion/page.tsx. No hay SQL. Se construye
// sobre el 246 (o cualquier build posterior); el resto de la pantalla
// queda intacto.
//
// Uso:
//   node generar_247_badge_medicamentos_fix.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: 'app/prevencion/page.tsx',
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('\nListo. 1 archivo escrito. git add / commit / push.')
} else {
  console.error('\nTerminó con ' + errores + ' error(es). NO hagas push.')
  process.exit(1)
}
